// Parameterized pipelined dot product engine. Accepts two input vectors A and B of length N, performs element-wise signed multiplication    followed by summation of partial products. The result is a single signed scalar value with a valid flag.

module dot_product (
    input clk,
    input rst,
    input A,
    input B,
    output reg dot_out,
    output reg valid
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dot_out <= 1'd0;
            valid <= 1'd0;
        end else begin
            // TODO: lower richer grammar rules into sequential behavior.
        end
    end

endmodule
